import { Notification, NotificationRepository } from './NotificationRepository';

export class NotificationNotFoundError extends Error {
  readonly code = 'NOTIFICATION_NOT_FOUND';

  constructor(id: string) {
    super(`Notification not found: ${id}`);
    this.name = 'NOTIFICATION_NOT_FOUND';
  }
}

export interface SendNotificationResult {
  notification: Notification;
  confirmed: boolean;
}

/**
 * NotificationService — Pattern A (direct interface injection).
 *
 * Follows the same constructor-injection contract used by OrderService,
 * ProductService, and WarehouseService.
 */
export class NotificationService {
  constructor(private readonly repo: NotificationRepository) {}

  /**
   * AC1: Given a userId and message, store the notification and return a confirmation.
   */
  async sendNotification(
    userId: string,
    message: string,
  ): Promise<SendNotificationResult> {
    const notification: Notification = {
      id: crypto.randomUUID(),
      userId,
      message,
      createdAt: new Date(),
    };

    const stored = await this.repo.save(notification);
    return { notification: stored, confirmed: true };
  }

  /**
   * AC2: Given an id, return the notification.
   * AC3: If not found, throw NOTIFICATION_NOT_FOUND.
   */
  async getNotification(id: string): Promise<Notification> {
    const notification = await this.repo.findById(id);

    if (!notification) {
      throw new NotificationNotFoundError(id);
    }

    return notification;
  }
}

