import { NotificationService, NotificationNotFoundError } from './NotificationService';
import { Notification, NotificationRepository } from './NotificationRepository';

// ---------------------------------------------------------------------------
// Test helpers
// ---------------------------------------------------------------------------

function makeRepo(overrides?: Partial<NotificationRepository>): NotificationRepository {
  return {
    save: async (n: Notification) => n,
    findById: async (_id: string) => null,
    ...overrides,
  };
}

// ---------------------------------------------------------------------------
// sendNotification — AC1
// ---------------------------------------------------------------------------

describe('NotificationService.sendNotification', () => {
  it('AC1: stores the notification and returns confirmed=true', async () => {
    const captured: Notification[] = [];
    const repo = makeRepo({
      save: async (n) => { captured.push(n); return n; },
    });
    const service = new NotificationService(repo);

    const result = await service.sendNotification('user-42', 'Your order shipped!');

    expect(captured).toHaveLength(1);
    expect(captured[0].userId).toBe('user-42');
    expect(captured[0].message).toBe('Your order shipped!');
    expect(typeof captured[0].id).toBe('string');
    expect(captured[0].id.length).toBeGreaterThan(0);
    expect(captured[0].createdAt).toBeInstanceOf(Date);

    expect(result.confirmed).toBe(true);
    expect(result.notification).toEqual(captured[0]);
  });

  it('AC1: returned notification matches what the repository persisted', async () => {
    const persisted: Notification = {
      id: 'repo-assigned-id',
      userId: 'user-1',
      message: 'Hello',
      createdAt: new Date('2026-01-01'),
    };
    // Simulate a repo that assigns its own id (e.g. DB-generated)
    const repo = makeRepo({ save: async () => persisted });
    const service = new NotificationService(repo);

    const result = await service.sendNotification('user-1', 'Hello');

    expect(result.notification).toEqual(persisted);
  });
});

// ---------------------------------------------------------------------------
// getNotification — AC2 & AC3
// ---------------------------------------------------------------------------

describe('NotificationService.getNotification', () => {
  it('AC2: returns the notification when it exists', async () => {
    const existing: Notification = {
      id: 'notif-1',
      userId: 'user-7',
      message: 'Welcome!',
      createdAt: new Date('2026-03-01'),
    };
    const repo = makeRepo({
      findById: async (id) => (id === 'notif-1' ? existing : null),
    });
    const service = new NotificationService(repo);

    const result = await service.getNotification('notif-1');

    expect(result).toEqual(existing);
  });

  it('AC3: throws NOTIFICATION_NOT_FOUND when notification does not exist', async () => {
    const repo = makeRepo({ findById: async () => null });
    const service = new NotificationService(repo);

    await expect(service.getNotification('ghost-id')).rejects.toThrow(
      NotificationNotFoundError,
    );
  });

  it('AC3: error code is NOTIFICATION_NOT_FOUND', async () => {
    const repo = makeRepo({ findById: async () => null });
    const service = new NotificationService(repo);

    try {
      await service.getNotification('ghost-id');
      fail('Expected error was not thrown');
    } catch (err) {
      expect(err).toBeInstanceOf(NotificationNotFoundError);
      expect((err as NotificationNotFoundError).code).toBe('NOTIFICATION_NOT_FOUND');
      expect((err as NotificationNotFoundError).name).toBe('NOTIFICATION_NOT_FOUND');
    }
  });

  it('AC3: error message includes the missing id', async () => {
    const repo = makeRepo({ findById: async () => null });
    const service = new NotificationService(repo);

    await expect(service.getNotification('notif-xyz')).rejects.toThrow('notif-xyz');
  });
});

